scripts.library_js:
// Shared HP helpers — available to every hook of this script.
var HP_MAX = 100;
function getHp() {
  if (typeof state.hp !== "number") state.hp = HP_MAX;
  return state.hp;
}
function setHp(value) {
  state.hp = Math.max(0, Math.min(HP_MAX, Math.round(value)));
  return state.hp;
}

scripts.context_js:
// Tell the AI the current HP and how to report changes it decides on.
var modifier = function (text) {
  var hp = getHp();
  var note =
    "\n\n[HP SYSTEM] The player currently has " + hp + " of " + HP_MAX + " HP. " +
    "You, the narrator, decide when and how much the player is hurt or healed based on the story. " +
    "When the player takes damage (an attack, trap, or fall) or heals (a potion, rest, or spell), " +
    "append a tag on its own line at the very end of your reply: [HP-N] for damage or [HP+N] for healing, " +
    "where N is a whole number. For example a solid sword blow might be [HP-14]; a healing potion might be [HP+25]. " +
    "Include the tag only when HP actually changes, and never explain or mention the tag in the prose.";
  return { text: text + note };
};
modifier(text);

scripts.output_js:
// Read the AI's [HP+N]/[HP-N] tags, apply them to state, hide them from the player.
var modifier = function (text) {
  var re = /\[HP([+-])(\d{1,3})\]/g;
  var hp = getHp();
  var changed = false;
  var m;
  while ((m = re.exec(text)) !== null) {
    var amount = parseInt(m[2], 10);
    hp += (m[1] === "-" ? -amount : amount);
    changed = true;
  }
  if (changed) setHp(hp);
  var clean = text
    .replace(/\[HP[+-]\d{1,3}\]/g, "")
    .replace(/[ \t]+\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
  if (changed && getHp() <= 0 && !state.dead) {
    state.dead = true;
    clean += "\n\nYour strength gives out and the world goes dark. (0 HP)";
  }
  return { text: clean };
};
modifier(text);
